Write-Host "=== STAGE 5: Islamic Finance ===" -ForegroundColor Cyan
Write-Host ""

$ROOT = "C:\ai-capitalS-mvp"
Set-Location $ROOT

function Deploy-Base64File {
    param([string]$Base64, [string]$FilePath)
    $dir = Split-Path $FilePath -Parent
    if (!(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
    $bytes = [System.Convert]::FromBase64String($Base64)
    [System.IO.File]::WriteAllBytes($FilePath, $bytes)
    Write-Host "  [OK] $FilePath" -ForegroundColor Green
}

Write-Host ""
Write-Host "1. Creating Stage 5 files..." -ForegroundColor Yellow

$b64_shariah = ""

$b64_zakat = ""

$b64_router = ""

Deploy-Base64File -Base64 $b64_shariah -FilePath "$ROOT\app\services\shariah_screening_service.py"
Deploy-Base64File -Base64 $b64_zakat   -FilePath "$ROOT\app\services\zakat_service.py"
Deploy-Base64File -Base64 $b64_router  -FilePath "$ROOT\app\api\v1\routers\islamic_finance.py"

Write-Host ""
Write-Host "2. Updating main.py..." -ForegroundColor Yellow

$mainPath = "$ROOT\app\main.py"
$mainContent = Get-Content $mainPath -Raw -Encoding UTF8

if ($mainContent -match "islamic_finance") {
    Write-Host "  [SKIP] islamic_finance already in main.py" -ForegroundColor DarkYellow
} else {
    $importLine = "from app.api.v1.routers import islamic_finance"
    $routerLine = 'app.include_router(islamic_finance.router, prefix="/api/v1")'

    if ($mainContent -match '(?m)^app\s*=\s*FastAPI') {
        $mainContent = $mainContent -replace '(?m)(^app\s*=\s*FastAPI)', "$importLine`n`n`$1"
    } else {
        $mainContent = $mainContent + "`n$importLine`n"
    }

    $mainContent = $mainContent.TrimEnd() + "`n`n# Stage 5: Islamic Finance`n$routerLine`n"

    [System.IO.File]::WriteAllText($mainPath, $mainContent, [System.Text.Encoding]::UTF8)
    Write-Host "  [OK] Added import + router islamic_finance" -ForegroundColor Green
}

