Write-Host ""
Write-Host "6. Testing Stage 5 endpoints..." -ForegroundColor Yellow

$passed = 0
$failed = 0

function Test-Endpoint {
    param([string]$Method, [string]$Url, [string]$Name, [string]$Body)
    try {
        if ($Method -eq "GET") {
            $resp = Invoke-RestMethod -Uri $Url -Method GET -TimeoutSec 10
        } else {
            $resp = Invoke-RestMethod -Uri $Url -Method POST -Body $Body -ContentType "application/json" -TimeoutSec 10
        }
        if ($resp.success -eq $true) {
            Write-Host "  [PASS] $Name" -ForegroundColor Green
            return $true
        } else {
            Write-Host "  [FAIL] $Name - success != true" -ForegroundColor Red
            return $false
        }
    } catch {
        Write-Host "  [FAIL] $Name - $($_.Exception.Message)" -ForegroundColor Red
        return $false
    }
}

$base = "http://localhost:8000/api/v1/islamic-finance"

if (Test-Endpoint "GET" "$base/reference/haram-industries" "Haram Industries") { $passed++ } else { $failed++ }
if (Test-Endpoint "GET" "$base/reference/financial-thresholds" "Financial Thresholds") { $passed++ } else { $failed++ }
