if (Test-Endpoint "GET" "$base/zakat/guide" "Zakat Guide") { $passed++ } else { $failed++ }
if (Test-Endpoint "POST" "$base/screening/industry" "Industry Screening" '{"company_name":"Coca-Cola","industry":"beverages","description":"Soft drinks"}') { $passed++ } else { $failed++ }
if (Test-Endpoint "POST" "$base/screening/financial" "Financial Screening" '{"company_name":"TestCorp","total_assets":1000000,"total_debt":200000,"total_revenue":500000,"haram_revenue":10000}') { $passed++ } else { $failed++ }
if (Test-Endpoint "POST" "$base/screening/full" "Full Screening" '{"company_name":"Uzpromstroybank","industry":"conventional banking","total_assets":5000000,"total_debt":1000000,"total_revenue":300000}') { $passed++ } else { $failed++ }
if (Test-Endpoint "POST" "$base/zakat/calculate" "Zakat Calculator" '{"assets":{"cash":50000000,"investments":100000000},"liabilities":{"loans":10000000},"currency":"UZS"}') { $passed++ } else { $failed++ }
if (Test-Endpoint "POST" "$base/zakat/reminder" "Zakat Reminder" '{"hawl_start":"2025-06-15","reminder_days_before":30}') { $passed++ } else { $failed++ }

